sql:
SELECT AVG(LENGTH(program_description)) AS avg_length
FROM programs
WHERE program_name LIKE '%History%' OR program_name LIKE '%Arts%';

WITH DescriptionLengths AS (
    SELECT program_id, LENGTH(program_description) as description_length
    FROM programs
),
CumulativeLengths AS (
    SELECT program_id, SUM(description_length) OVER (ORDER BY program_id) as cumulative_length
    FROM DescriptionLengths
)
SELECT MIN(cumulative_length) AS min_cumulative_length
FROM CumulativeLengths;

SELECT IFNULL(program_name, 'No program name available') AS program_name
FROM programs
WHERE program_id > 0;

external_knowledge:
- "program_name" refers to the name of the program;
- "program_description" provides details about the program;
- "program_id" is a unique identifier for each program;
- "LENGTH(program_name)" calculates the length of the program name;
- "MAX(LENGTH(program_name)) OVER ()" finds the maximum length of any program name in the table.

sql:
SELECT program_name 
FROM programs 
WHERE program_description LIKE '%history%';

SELECT COUNT(*) AS program_count
FROM programs
WHERE program_id > 0;

SELECT AVG(SIN(program_id)) AS average_sine
FROM programs
WHERE LENGTH(program_name) > (SELECT AVG(LENGTH(program_name)) FROM programs);

SELECT program_name 
FROM programs
WHERE LENGTH(program_description) = (
    SELECT MAX(LENGTH(program_description)) 
    FROM programs
);

SELECT program_name
FROM programs
WHERE program_description LIKE '%history%' OR program_description LIKE '%degree program%';

external_knowledge:
- 'Undergraduate' programs typically include Bachelor's degrees;
- 'Graduate' programs typically include Master's degrees;
- 'Other' programs include any other types of academic programs not categorized as Undergraduate or Graduate.

sql:
SELECT DISTINCT program_name
FROM programs
WHERE program_name LIKE 'Bachelor%' OR program_name LIKE 'Master%';

SELECT program_name
FROM programs
WHERE LENGTH(program_description) > 2 * LENGTH(program_name);

SELECT program_name
FROM programs
ORDER BY LENGTH(program_name) DESC;

SELECT program_name
FROM programs
WHERE LENGTH(program_name) = (
  SELECT MAX(LENGTH(program_name)) FROM programs
);

